## Task 4: Retriever Trait + VectorRetriever

    use crate::lite_store::LiteStore;
    use corvia_common::types::KnowledgeEntry;

    struct MockEngine;
    #[async_trait]
    impl InferenceEngine for MockEngine {
        async fn embed(&self, _text: &str) -> corvia_common::errors::Result<Vec<f32>> {
            Ok(vec![1.0, 0.0, 0.0])
        }
        async fn embed_batch(&self, texts: &[String]) -> corvia_common::errors::Result<Vec<Vec<f32>>> {
            Ok(texts.iter().map(|_| vec![1.0, 0.0, 0.0]).collect())
        }
        fn dimensions(&self) -> usize { 3 }
    }

    #[tokio::test]
    async fn test_vector_retriever_basic_search() {
        let dir = tempfile::tempdir().unwrap();
        let store = Arc::new(LiteStore::open(dir.path(), 3).unwrap()) as Arc<dyn QueryableStore>;
        let engine = Arc::new(MockEngine) as Arc<dyn InferenceEngine>;
        store.init_schema().await.unwrap();

        // Insert entries with slightly varied embeddings for HNSW connectivity
        let mut idx = 0_usize;
        let mut next_emb = || { idx += 1; vec![1.0, idx as f32 * 0.001, 0.0] };

        let mut e1 = KnowledgeEntry::new("auth module".into(), "proj".into(), "v1".into())
            .with_embedding(next_emb());
        e1.entry_status = EntryStatus::Merged;
        store.insert(&e1).await.unwrap();

        let mut e2 = KnowledgeEntry::new("database layer".into(), "proj".into(), "v1".into())
